   223 |   case Instruction::Add:
   224 |   case Instruction::FAdd:
   225 |   case Instruction::Mul:
   226 |   case Instruction::FMul:
   227 |   case Instruction::And:
   228 |   case Instruction::Or:
   229 |   case Instruction::Xor:
